import { mkdir } from "node:fs/promises";
import path from "node:path";
import QRCode from "qrcode";
import { normalizeText, toQrOptions } from "./shared.js";
export async function renderSvg(text, options = {}) {
    return await QRCode.toString(normalizeText(text), {
        ...toQrOptions(options),
        type: "svg",
    });
}
export async function writeSvgFile(text, filePath, options = {}) {
    if (typeof filePath !== "string" || filePath.trim().length === 0) {
        throw new Error("SVG output path must not be empty.");
    }
    await mkdir(path.dirname(filePath), { recursive: true });
    await QRCode.toFile(filePath, normalizeText(text), {
        ...toQrOptions(options),
        type: "svg",
    });
    return filePath;
}
